module counter_32bit (
    input clk,
    input rst,
    input en,
    output reg [31:0] count
);
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            count <= 32'b0;
        end else if (en) begin
            count <= count + 1;
        end
    end
endmodule
